task_02.Answer:
type DataInput = string | number | { value: number } | null | undefined;

function isObject(input: unknown): input is { value: number } {
  return typeof input === 'object' && input !== null && 'value' in input;
}

function processData(input: DataInput): string {
  if (input === null || input === undefined) {
    return "NULL/UNDEFINED";
  }

  if (typeof input === "string") {
    return `STRING: ${input}`;
  }

  if (typeof input === "number") {
    return `NUMBER: ${input}`;
  }

  if (isObject(input)) {
    return `OBJECT: ${input.value}`;
  }

  const _exhaustive: never = input;
  return _exhaustive;
}

export function Answer() {
  const testCases = [
    { input: "hello", expected: "STRING: hello" },
    { input: 42, expected: "NUMBER: 42" },
    { input: { value: 100 }, expected: "OBJECT: 100" },
    { input: null, expected: "NULL/UNDEFINED" },
    { input: undefined, expected: "NULL/UNDEFINED" },
  ];

  return (
    <div style={{ padding: '20px' }}>
      <h2>✅ Task 2: TypeScript Type Narrowing (Solution)</h2>
      <div style={{ padding: '20px', border: '1px solid #4caf50', backgroundColor: '#f1f8e9' }}>
        {testCases.map((tc, i) => (
          <div 
            key={i} 
            style={{ 
              padding: '10px', 
              margin: '5px', 
              backgroundColor: '#ffffff',
              border: '1px solid #4caf50'
            }}
          >
            <strong>Input:</strong> {JSON.stringify(tc.input)} → <strong style={{color: '#4caf50'}}>{processData(tc.input as DataInput)}</strong>
          </div>
