task_04.Answer:
import React, { useState } from "react";

class TimeoutError extends Error {
  constructor(message = "Request timeout") {
    super(message);
    this.name = "TimeoutError";
  }
}

function fetchWithTimeout(url, timeoutMs) {
  const controller = new AbortController();
  const timeoutId = setTimeout(() => controller.abort(), timeoutMs);

  return fetch(url, { signal: controller.signal })
    .then(response => {
      clearTimeout(timeoutId);
      if (!response.ok) throw new Error(`HTTP ${response.status}`);
      return response.json();
    })
    .catch(error => {
      clearTimeout(timeoutId);
      if (error.name === "AbortError") {
        throw new TimeoutError(`Request timeout after ${timeoutMs}ms`);
      }
      throw error;
    });
}

export function Answer() {
  const [result, setResult] = useState("");
  const [loading, setLoading] = useState(false);

  const testSuccess = async () => {
    setLoading(true);
    try {
      const data = await fetchWithTimeout(
        "https://jsonplaceholder.typicode.com/posts/1",
        5000
      );
      setResult(`✓ Success: ${data.title}`);
    } catch (error) {
      setResult(`✗ Error: ${error.message}`);
    } finally {
      setLoading(false);
    }
  };

  const testTimeout = async () => {
    setLoading(true);
    try {
      const data = await fetchWithTimeout(
        "https://jsonplaceholder.com/slow-endpoint",
        1000
      );
      setResult(`Success: ${data.title}`);
    } catch (error) {
      setResult(`✓ Caught timeout: ${error.name}`);
    } finally {
      setLoading(false);
    }
  };

  return (
    <div style={{ padding: '20px' }}>
      <h2>✅ Task 4: Promise Race & Timeout (Solution)</h2>
      <div style={{ marginBottom: '20px' }}>
        <button onClick={testSuccess} disabled={loading}>
          Test Success (5s timeout)
        </button>
        <button onClick={testTimeout} disabled={loading} style={{ marginLeft: '10px' }}>
          Test Timeout (1s)
        </button>
      </div>
      <div style={{
        padding: '15px',
        border: '1px solid #4caf50',
        backgroundColor: '#f1f8e9',
        borderRadius: '4px'
      }}>
        {result || (loading ? "Loading..." : "Click to test")}
      </div>
    </div>
  );
}

