import React, { useReducer, useEffect, useState } from "react";

const ACTIONS = {
  ADD_ITEM: 'ADD_ITEM',
  REMOVE_ITEM: 'REMOVE_ITEM',
  TOGGLE_ITEM: 'TOGGLE_ITEM',
  CLEAR_ALL: 'CLEAR_ALL',
  UNDO: 'UNDO',
  REDO: 'REDO',
};

const initialState = {
  items: [],
  history: [[]],
  historyIndex: 0,
};

function todoReducer(state, action) {
  let newItems;

  switch (action.type) {
    case ACTIONS.ADD_ITEM: {
      if (!action.payload.text.trim()) return state;

      newItems = [
        ...state.items,
        {
          id: Date.now(),
          text: action.payload.text,
          completed: false,
        },
      ];
      break;
    }

    case ACTIONS.REMOVE_ITEM:
      newItems = state.items.filter(item => item.id !== action.payload.id);
      break;

    case ACTIONS.TOGGLE_ITEM:
      newItems = state.items.map(item =>
        item.id === action.payload.id
          ? { ...item, completed: !item.completed }
          : item
      );
      break;

    case ACTIONS.CLEAR_ALL:
      newItems = [];
      break;

    case ACTIONS.UNDO:
      if (state.historyIndex > 0) {
        return {
          ...state,
          historyIndex: state.historyIndex - 1,
          items: state.history[state.historyIndex - 1],
        };
      }
      return state;

    case ACTIONS.REDO:
      if (state.historyIndex < state.history.length - 1) {
        return {
          ...state,
          historyIndex: state.historyIndex + 1,
          items: state.history[state.historyIndex + 1],
        };
      }
      return state;

    default:
      return state;
  }

  if (newItems !== undefined) {
    const newHistory = state.history.slice(0, state.historyIndex + 1);
    newHistory.push(newItems);

    return {
      items: newItems,
      history: newHistory,
      historyIndex: newHistory.length - 1,
    };
  }

  return state;
}

export function Answer() {
  const [state, dispatch] = useReducer(todoReducer, initialState);
  const [input, setInput] = useState("");

  useEffect(() => {
    localStorage.setItem('todoState', JSON.stringify(state));
  }, [state]);

  const handleAddTodo = () => {
    dispatch({ type: ACTIONS.ADD_ITEM, payload: { text: input } });
    setInput("");
  };

  const canUndo = state.historyIndex > 0;
  const canRedo = state.historyIndex < state.history.length - 1;

  return (
    <div style={{ padding: '20px' }}>
      <h2>✅ Task 6: Reducer Pattern - Todo App</h2>

      <div style={{ marginBottom: '20px' }}>
        <input
          type="text"
          value={input}
          onChange={(e) => setInput(e.target.value)}
          onKeyPress={(e) => e.key === 'Enter' && handleAddTodo()}
          placeholder="Add a new todo..."
          style={{ padding: '8px', marginRight: '10px', width: '200px' }}
        />
        <button onClick={handleAddTodo}>Add</button>
        <button 
          onClick={() => dispatch({ type: ACTIONS.UNDO })}
          disabled={!canUndo}
          style={{ marginLeft: '10px' }}
        >
          ↶ Undo
        </button>
        <button 
          onClick={() => dispatch({ type: ACTIONS.REDO })}
          disabled={!canRedo}
          style={{ marginLeft: '5px' }}
        >
          ↷ Redo
        </button>
      </div>

      <div style={{ 
        border: '1px solid #4caf50',
        borderRadius: '4px',
        padding: '15px',
        backgroundColor: '#f1f8e9'
      }}>
        {state.items.length === 0 ? (
          <p>No todos yet</p>
        ) : (
          <ul style={{ listStyle: 'none' }}>
            {state.items.map(item => (
              <li 
                key={item.id}
                style={{
                  padding: '10px',
                  marginBottom: '8px',
                  backgroundColor: 'white',
                  borderRadius: '4px',
                  display: 'flex',
                  justifyContent: 'space-between',
                }}
              >
                <label style={{ display: 'flex', alignItems: 'center' }}>
                  <input
                    type="checkbox"
