function flattenObject(obj, prefix = '') {
  const flattened = {};

  for (const key in obj) {
    if (!obj.hasOwnProperty(key)) continue;

    const value = obj[key];
    const newKey = prefix ? `${prefix}.${key}` : key;

    if (
      value !== null &&
      typeof value === 'object' &&
      !Array.isArray(value) &&
      typeof value !== 'function'
    ) {
      Object.assign(flattened, flattenObject(value, newKey));
    } else if (Array.isArray(value)) {
      value.forEach((item, index) => {
        const arrayKey = `${newKey}.${index}`;
        if (item !== null && typeof item === 'object') {
          Object.assign(flattened, flattenObject(item, arrayKey));
        } else {
          flattened[arrayKey] = item;
        }
      });
    } else if (value !== undefined && typeof value !== 'function') {
      flattened[newKey] = value;
    }
  }

  return flattened;
}

function unflattenObject(obj) {
  const result = {};

  for (const key in obj) {
    const keys = key.split('.');
    let current = result;

    for (let i = 0; i < keys.length - 1; i++) {
      const k = keys[i];
      const nextK = keys[i + 1];
      const isArrayIndex = /^d+$/.test(nextK);

      if (!current[k]) {
        current[k] = isArrayIndex ? [] : {};
      }
      current = current[k];
    }

    const lastKey = keys[keys.length - 1];
    current[lastKey] = obj[key];
  }

  return result;
}

