import React, { useEffect, useState, useRef } from "react";

export function Answer() {
  const [data, setData] = useState(null);
  const [loading, setLoading] = useState(true);
  const [error, setError] = useState(null);
  const [windowSize, setWindowSize] = useState({
    width: typeof window !== 'undefined' ? window.innerWidth : 0,
    height: typeof window !== 'undefined' ? window.innerHeight : 0,
  });
  const abortControllerRef = useRef(null);

  // Эффект 1: Загрузка данных при монтировании
  useEffect(() => {
    abortControllerRef.current = new AbortController();

    const fetchData = async () => {
      try {
        setLoading(true);
        const response = await fetch(
          'https://jsonplaceholder.typicode.com/posts/1',
          { signal: abortControllerRef.current.signal }
        );
        if (!response.ok) throw new Error('Failed to fetch');
        const result = await response.json();
        setData(result);
      } catch (err) {
        if (err.name !== 'AbortError') {
          setError(err.message);
        }
      } finally {
        setLoading(false);
      }
    };

    fetchData();

    // Cleanup функция при размонтировании
    return () => {
      abortControllerRef.current?.abort();
    };
  }, []); // Пустой массив зависимостей = запуск только при монтировании

  // Эффект 2: Отслеживание размера окна
  useEffect(() => {
    const handleResize = () => {
      setWindowSize({
        width: window.innerWidth,
        height: window.innerHeight,
      });
    };

    window.addEventListener('resize', handleResize);

    // Cleanup: удаляем слушатель события
    return () => {
      window.removeEventListener('resize', handleResize);
    };
  }, []); // Пустой массив зависимостей

  return (
    <div style={{ padding: '20px' }}>
      <h2>✅ Task 8: React Lifecycle (Solution)</h2>

      <div style={{ 
        padding: '15px', 
        marginBottom: '15px',
        border: '1px solid #4caf50',
        backgroundColor: '#f1f8e9',
        borderRadius: '4px'
      }}>
        <h3>Window Size:</h3>
        <p>{windowSize.width} × {windowSize.height}</p>
        <p style={{ fontSize: '12px', color: '#666' }}>Try resizing the window</p>
      </div>

      <div style={{ 
        padding: '15px',
        border: '1px solid #4caf50',
        backgroundColor: '#f1f8e9',
        borderRadius: '4px'
      }}>
        <h3>Fetched Data:</h3>
        {loading && <p>Loading...</p>}
        {error && <p style={{ color: 'red' }}>Error: {error}</p>}
        {data && (
          <>
            <p><strong>Title:</strong> {data.title}</p>
            <p><strong>Body:</strong> {data.body.substring(0, 100)}...</p>
          </>
        )}
      </div>

      <div style={{ marginTop: '20px', fontSize: '12px', color: '#666' }}>
        <p>✓ Data loaded on component mount</p>
        <p>✓ Resize listener cleaned up on unmount</p>
        <p>✓ Fetch request aborted on unmount</p>
        <p>✓ No memory leaks</p>
      </div>
    </div>
  );
}

