import React, { useState } from "react";

// Утилиты для работы с Promise

// 1. Retry функция
function retry(fn, maxAttempts = 3, delay = 1000) {
  return fn().catch(err => {
    if (maxAttempts <= 1) throw err;
    return new Promise(resolve => setTimeout(resolve, delay))
      .then(() => retry(fn, maxAttempts - 1, delay));
  });
}

// 2. Timeout обертка
function timeout(promise, ms) {
  return Promise.race([
    promise,
    new Promise((_, reject) =>
      setTimeout(() => reject(new Error(`Timeout after ${ms}ms`)), ms)
    )
  ]);
}

// 3. Параллельное выполнение с контролем
function parallel(promises, maxConcurrent = 3) {
  const results = [];
  let index = 0;

  function runNext() {
    if (index >= promises.length) {
      return Promise.resolve();
    }
    const currentIndex = index++;
    return Promise.resolve(promises[currentIndex]).then(result => {
      results[currentIndex] = result;
      return runNext();
    });
  }

  const workers = [];
  for (let i = 0; i < Math.min(maxConcurrent, promises.length); i++) {
    workers.push(runNext());
  }

  return Promise.all(workers).then(() => results);
}

// 4. Последовательное выполнение
function sequential(fns) {
  return fns.reduce(
    (promise, fn) => promise.then(results => 
      Promise.resolve(fn()).then(result => [...results, result])
    ),
    Promise.resolve([])
  );
}

// 5. Race функция (уже есть в Promise.race)
function race(promises) {
  return Promise.race(promises);
}

