      setResults(prev => ({ ...prev, retry: 'Success after retry' }));
    } catch (err) {
      setResults(prev => ({ ...prev, retry: 'Failed: ' + err.message }));
    } finally {
      setLoading(false);
    }
  };

  const testTimeout = async () => {
