        <h3>2. Render Props - MouseTracker</h3>
        <MouseTracker render={(pos) => (
          <p>Mouse position: X={Math.round(pos.x)}, Y={Math.round(pos.y)}</p>
        )} />
      </div>

      {/* 3. HOC */}
      <div style={{ marginBottom: '20px', padding: '15px', border: '1px solid #4caf50', backgroundColor: '#f1f8e9', borderRadius: '4px' }}>
        <h3>3. HOC - withTheme</h3>
        <ThemedDisplay />
      </div>

      {/* 4. Context API */}
      <div style={{ marginBottom: '20px', padding: '15px', border: '1px solid #4caf50', backgroundColor: '#f1f8e9', borderRadius: '4px' }}>
        <h3>4. Context API</h3>
        <CounterProvider>
          <ContextConsumer />
        </CounterProvider>
      </div>

      <p style={{ marginTop: '15px', fontSize: '12px', color: '#666' }}>
        ✓ Custom Hook for encapsulation<br/>
        ✓ Render Props for composition<br/>
        ✓ HOC for logic wrapping<br/>
        ✓ Context for global state
      </p>
    </div>
  );
}
